#include <stdio.h>
#include <stdlib.h>

// Function to apply thresholding to an image
void thresholding(int **image, int threshold, int width, int height) {
 for (int i = 0; i < height; i++) {
 for (int j = 0; j < width; j++) {
 if (image[i][j] > threshold) {
 image[i][j] = 255;
 } else {
 image[i][j] = 0;
 }
 }
 }
}

int main() {
 // Load the image
 int **image = (int **)malloc(100 * sizeof(int *));
 for (int i = 0; i < 100; i++) {
 image[i] = (int *)malloc(100 * sizeof(int));
 }

 // Apply thresholding
 thresholding(image, 127, 100, 100);

 // Print the segmented image
 for (int i = 0; i < 100; i++) {
 for (int j = 0; j < 100; j++) {
 printf("%d ", image[i][j]);
 }
 printf("\n");
 }

 return 0;
}
